import{_ as o,o as t,c as e,V as s}from"./chunks/framework.9f252c2a.js";const m=JSON.parse('{"title":"操作系统的特权级机制","description":"","frontmatter":{"group":"操作系统","title":"操作系统的特权级机制","layout":"doc","date":"2022-12-30T05:54:36.000Z","tags":["os","risc-v"],"sidebar":true,"summary":"特权级是为了隔离操作系统中用户程序与操作系统的,主要是防止用户程序的错误不会导致操作系统的一种机制.","order":100},"headers":[],"relativePath":"content/docs/os/os-1.md"}'),l={name:"content/docs/os/os-1.md"},r=s('<h2 id="特权级的软硬件协同设计" tabindex="-1">特权级的软硬件协同设计 <a class="header-anchor" href="#特权级的软硬件协同设计" aria-label="Permalink to &quot;特权级的软硬件协同设计&quot;">​</a></h2><p>实现特权级机制的根本原因是<strong>应用程运行的安全性不可充分信任</strong> .所以,计算机科学家和工程师想到了一个方法：让相对安全可靠的操作系统运行在一个硬件保护的安全执行环境中,不受到程序的破坏；而让应用程序运行在另外一个无法破坏操作系统的受限执行环境中.</p><ul><li>应用程序不能随意访问地址空间</li><li>应用程序不能执行某些可能破坏计算机系统的指令</li></ul><p>同时为了应用程序能获得操作系统的服务——应用程序和操作系统还需要有交互的手段.</p><ul><li>低特权级的软件只能做高特权级允许它做的操作</li><li>超出低特权级能力的功能必须寻求高特权级的帮助</li></ul><p>这样<strong>高特权级</strong>(操作系统)就成为<strong>低特权级</strong>（一般应用）的<strong>执行环境的总要组成部分</strong>.</p><p>为了实现这样的特权级机制,需要进行软硬件协同设计.一种简介的方式是： 处理器设置两个不同安全等级的执行环境,<strong>用户态特权级的执行环境和内核态特权级的执行环境</strong>.</p><ul><li>明确指出可能破坏计算机系统的内核态特权指令集子集</li><li>规定内核态特权级指令子集中的指令只能在内核态特权级的执行环境中执行</li><li>处理器在执行指令前会进行特权级安全检查,如果在用户态环境中执行内核态特权级指令就会产生异常</li></ul><p>传统的<code>call</code>和<code>ret</code>指令组合会直接绕过硬件的特权级保护检查,所以需要新的指令：</p><ul><li><code>ecall</code>： 执行环境调用,具有<strong>用户态</strong>到<strong>内核态</strong>的执行环境切换能力的<strong>函数调用</strong>指令 <ul><li>从当前特权级切换到比当前高一级</li></ul></li><li><code>eret</code>： 执行环境返回,基友<strong>内核态</strong>到<strong>用户态</strong>的执行环境切换能力的<strong>函数返回</strong>指令 <ul><li>切换到不高于当前特权级</li></ul></li></ul><p>硬件有了这样的机制之后,还需要操作系统的配合才能完成对操作系统自身的保护.</p><ol><li>操作系统需要提供能在执行<code>eret</code>前<strong>准备和恢复用户态执行应用程序的上下文</strong></li><li>在用户程序调用<code>ecall</code>后能<strong>检查应用程序的系统调用参数</strong>,确保参数不会破坏操作系统</li></ol>',12),n=[r];function i(c,a,d,g,_,p){return t(),e("div",null,n)}const h=o(l,[["render",i]]);export{m as __pageData,h as default};
